## Handler (key excerpt)

```typescript
export function makePatchUserEmail(userRepository: UserRepository) {
  return async function patchUserEmail(req, res) {
    const { id } = req.params;
    const { email } = req.body;

    // AC3 — format guard (before any DB call)
    if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
      return res.status(400).json({ error: { code: 'INVALID_EMAIL_FORMAT', ... } });
    }

    // AC4 — existence guard
    const user = await userRepository.findById(id);
    if (!user) {
      return res.status(404).json({ error: { code: 'USER_NOT_FOUND', ... } });
    }

    // AC5 — idempotency short-circuit (skips findByEmail, no write)
    if (user.email === email) {
      return res.status(200).json({ user });
    }

    // AC2 — uniqueness guard
    const existing = await userRepository.findByEmail(email);
    if (existing) {
      return res.status(409).json({ error: { code: 'EMAIL_ALREADY_IN_USE', ... } });
    }

    // AC1 — happy path
    const updatedUser = await userRepository.updateEmail(id, email);
    res.status(200).json({ user: updatedUser });
  };
}
```

